import numpy as np

class Board:
    def __init__(self):
        self.board = np.zeros((8, 8), dtype=int)
        self.setup_board()

    def setup_board(self):
        # Initialize the board with pieces
        for i in range(3):
            for j in (1, 3, 5, 7):
                self.board[i][j] = -1
            for j in (0, 2, 4, 6):
                self.board[7-i][j] = 1

    def move_piece(self, from_pos, to_pos):
        row_from, col_from = from_pos
        row_to, col_to = to_pos
        piece = self.board[row_from][col_from]
        if abs(row_to - row_from) == 2 and abs(col_to - col_from) == 2:
            # Capture piece
            self.board[(row_from + row_to) // 2][(col_from + col_to) // 2] = 0
        self.board[row_from][col_from] = 0
        self.board[row_to][col_to] = piece

    def __str__(self):
        return '\n'.join([' '.join(map(str, row)) for row in self.board])
```

